const opps = $input.all().map(i => i.json);
const risks = [];

for (const opp of opps) {
  if (!opp.opp_id) continue;

  // CRITICAL: Deadline <=30d + no capture plan
  if (opp.deadline_imminent && !opp.has_capture_plan) {
    risks.push({
      risk_key: `deadline-nocapture-${opp.opp_id}`,
      title: `URGENT: ${(opp.opp_title || 'Unknown').substring(0, 80)} - deadline <=30d, no capture plan`,
      severity: 'CRITICAL',
      category: 'Capture Gap',
      owner: 'Shawn',
      opp_id: opp.opp_id,
      agency: opp.agency || 'Unknown',
      description: `Opportunity "${opp.opp_title}" has a deadline within 30 days but no capture plan exists. GDA Score: ${opp.gda_score}, Label: ${opp.gda_label}, Est. Value: $${(opp.estimated_value || 0).toLocaleString()}.`,
      mitigation: 'Run auto-capture immediately. Assign BD lead. Review win themes.',
      due_date: opp.response_deadline || null
    });
  }

  // HIGH: PURSUE opp + no capture plan
  if (opp.gda_label === 'PURSUE' && !opp.has_capture_plan && !opp.deadline_imminent) {
    risks.push({
      risk_key: `pursue-nocapture-${opp.opp_id}`,
      title: `PURSUE opp missing capture plan: ${(opp.opp_title || 'Unknown').substring(0, 80)}`,
      severity: 'HIGH',
      category: 'Capture Gap',
      owner: 'Shawn',
      opp_id: opp.opp_id,
      agency: opp.agency || 'Unknown',
      description: `PURSUE-rated opportunity (GDA Score: ${opp.gda_score}) has no capture plan. Est. Value: $${(opp.estimated_value || 0).toLocaleString()}.`,
      mitigation: 'Generate capture plan via auto-capture workflow. Review competitive positioning.',
      due_date: opp.response_deadline || null
    });
  }

  // HIGH: Deadline <=60d for PURSUE opps
  if (opp.gda_label === 'PURSUE' && opp.deadline_near && !opp.deadline_imminent) {
    risks.push({
      risk_key: `recompete-near-${opp.opp_id}`,
      title: `Recompete approaching (<=60d): ${(opp.opp_title || 'Unknown').substring(0, 80)}`,
      severity: 'HIGH',
      category: 'Recompete',
      owner: 'Shawn',
      opp_id: opp.opp_id,
      agency: opp.agency || 'Unknown',
      description: `PURSUE opportunity deadline within 60 days. Stage: ${opp.stage}. Needs active pursuit.`,
      mitigation: 'Accelerate teaming discussions. Lock key personnel. Finalize pricing strategy.',
      due_date: opp.response_deadline || null
    });
  }

  // MEDIUM: $10M+ opp with no capture plan
  if (opp.high_value && !opp.has_capture_plan && opp.gda_label !== 'PURSUE') {
    risks.push({
      risk_key: `highval-nocapture-${opp.opp_id}`,
      title: `$10M+ opp uncaptured: ${(opp.opp_title || 'Unknown').substring(0, 80)}`,
      severity: 'MEDIUM',
      category: 'Pipeline',
      owner: 'BD Team',
      opp_id: opp.opp_id,
      agency: opp.agency || 'Unknown',
      description: `High-value opportunity ($${(opp.estimated_value || 0).toLocaleString()}) rated ${opp.gda_label} has no capture plan.`,
      mitigation: 'Evaluate for upgrade to PURSUE. Generate preliminary capture plan.',
      due_date: null
    });
  }

  // MEDIUM: Department concentration >40%
  if (opp.dept_concentration_pct && opp.dept_concentration_pct > 40) {
    const deptKey = `dept-concentration-${(opp.dept || 'unknown').replace(/[^a-zA-Z0-9]/g, '-')}`;
    if (!risks.find(r => r.risk_key === deptKey)) {
      risks.push({
        risk_key: deptKey,
        title: `Department concentration risk: ${opp.dept} (${Math.round(opp.dept_concentration_pct)}% of pipeline)`,
        severity: 'MEDIUM',
        category: 'Concentration',
        owner: 'Shawn',
        opp_id: null,
        agency: opp.agency || 'Unknown',
        description: `${Math.round(opp.dept_concentration_pct)}% of PURSUE/EVALUATE pipeline is concentrated in ${opp.dept}. Revenue risk if agency budget cuts occur.`,
        mitigation: 'Diversify pipeline across agencies. Target new departments.',
        due_date: null
      });
    }
  }
}

if (risks.length === 0) {
  return [{json: {_noRisks: true, message: 'No risks generated'}}];
}

return [{json: {risks: risks, count: risks.length}}];

