DO $$ BEGIN
  -- Add risk_key column if table exists but column doesn't
  IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'gda_risk_register') 
     AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'gda_risk_register' AND column_name = 'risk_key') THEN
    ALTER TABLE gda_risk_register ADD COLUMN risk_key VARCHAR(255) UNIQUE;
    ALTER TABLE gda_risk_register ADD COLUMN IF NOT EXISTS auto_generated BOOLEAN DEFAULT true;
    ALTER TABLE gda_risk_register ADD COLUMN IF NOT EXISTS source VARCHAR(50) DEFAULT 'auto-risk-cron';
    ALTER TABLE gda_risk_register ADD COLUMN IF NOT EXISTS agency VARCHAR(255);
    ALTER TABLE gda_risk_register ADD COLUMN IF NOT EXISTS opp_id INTEGER;
    ALTER TABLE gda_risk_register ADD COLUMN IF NOT EXISTS description TEXT;
    ALTER TABLE gda_risk_register ADD COLUMN IF NOT EXISTS mitigation TEXT;
    ALTER TABLE gda_risk_register ADD COLUMN IF NOT EXISTS due_date DATE;
    ALTER TABLE gda_risk_register ADD COLUMN IF NOT EXISTS updated_at TIMESTAMP DEFAULT NOW();
    ALTER TABLE gda_risk_register ADD COLUMN IF NOT EXISTS created_at TIMESTAMP DEFAULT NOW();
    ALTER TABLE gda_risk_register ADD COLUMN IF NOT EXISTS status VARCHAR(20) DEFAULT 'OPEN';
  END IF;
END $$;

CREATE TABLE IF NOT EXISTS gda_risk_register (
  id SERIAL PRIMARY KEY,
  risk_key VARCHAR(255) UNIQUE,
  title TEXT NOT NULL,
  severity VARCHAR(20) NOT NULL DEFAULT 'MEDIUM',
  category VARCHAR(50),
  owner VARCHAR(100),
  opp_id INTEGER,
  agency VARCHAR(255),
  description TEXT,
  mitigation TEXT,
  status VARCHAR(20) DEFAULT 'OPEN',
  due_date DATE,
  created_at TIMESTAMP DEFAULT NOW(),
  updated_at TIMESTAMP DEFAULT NOW(),
  auto_generated BOOLEAN DEFAULT true,
  source VARCHAR(50) DEFAULT 'auto-risk-cron'
);
CREATE INDEX IF NOT EXISTS idx_risk_register_severity ON gda_risk_register(severity);
CREATE INDEX IF NOT EXISTS idx_risk_register_status ON gda_risk_register(status);
CREATE INDEX IF NOT EXISTS idx_risk_register_risk_key ON gda_risk_register(risk_key);

