const data = $('Generate Risk Records').first().json;
const risks = data.risks || [];

const queries = risks.map(r => {
  const esc = (s) => (s || '').replace(/'/g, "''").replace(/\$/g, 'USD ');
  const title = esc(r.title);
  const desc = esc(r.description);
  const mitigation = esc(r.mitigation);
  const agency = esc(r.agency);
  const owner = esc(r.owner || 'Shawn');
  const category = esc(r.category || 'General');
  const dueDate = r.due_date ? `'${r.due_date}'` : 'NULL';
  const oppId = r.opp_id || 'NULL';

  return `INSERT INTO gda_risk_register (risk_key, title, severity, category, owner, opp_id, agency, description, mitigation, due_date, auto_generated, updated_at)
    VALUES ('${r.risk_key}', '${title}', '${r.severity}', '${category}', '${owner}', ${oppId}, '${agency}', '${desc}', '${mitigation}', ${dueDate}, true, NOW())
    ON CONFLICT (risk_key) DO UPDATE SET
      title = EXCLUDED.title,
      severity = EXCLUDED.severity,
      description = EXCLUDED.description,
      mitigation = EXCLUDED.mitigation,
      due_date = EXCLUDED.due_date,
      updated_at = NOW()
    WHERE gda_risk_register.status = 'OPEN';`;
});

queries.push(`UPDATE gda_risk_register SET status = 'RESOLVED', updated_at = NOW()
  WHERE auto_generated = true AND status = 'OPEN'
  AND risk_key NOT IN (${risks.map(r => "'" + r.risk_key + "'").join(',') || "'__none__'"})`);

return [{json: {query: queries.join('\n'), risk_count: risks.length}}];
